const { Storage } = require('@google-cloud/storage');
const express = require('express');
const app = express();
const storage = new Storage();

app.get('/serve-file', async (req, res) => {
  try {
    const bucketName = req.query.bucket;
    const filePath = req.query.file;

    // Validate bucket and file path
    if (!bucketName || !filePath) {
      return res.status(400).send('Bucket and file path must be specified.');
    }

    // Allowlist for bucket names (example: replace with actual bucket names)
    const allowedBuckets = ['my-allowed-bucket1', 'my-allowed-bucket2'];
    if (!allowedBuckets.includes(bucketName)) {
      return res.status(403).send('Access to the specified bucket is not allowed.');
    }

    const bucket = storage.bucket(bucketName);
    const file = bucket.file(filePath);

    // Check if file exists
    const [exists] = await file.exists();
    if (!exists) {
      return res.status(404).send('File not found.');
    }

    // Stream the file to the response
    res.setHeader('Content-Disposition', `attachment; filename="${filePath.split('/').pop()}"`);
    file.createReadStream()
      .on('error', (err) => {
        console.error('Error reading file:', err);
        res.status(500).send('Internal Server Error');
      })
      .pipe(res);
  } catch (error) {
    console.error('Error serving file:', error);
    res.status(500).send('Internal Server Error');
  }
});

const PORT = process.env.PORT || 8080;
app.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});